// @solace/client-sdk

/**
 * Generates a random AES-GCM 256 key.
 * @returns {Promise<CryptoKey>}
 */
async function generateKey() {
  return crypto.subtle.generateKey({ name: "AES-GCM", length: 256 }, true, [
    "encrypt",
    "decrypt",
  ]);
}

/**
 * Imports a raw key (Uint8Array or ArrayBuffer) as AES-GCM 256.
 * @param {ArrayBuffer|Uint8Array} rawKey
 * @returns {Promise<CryptoKey>}
 */
async function importKey(rawKey) {
  return crypto.subtle.importKey("raw", rawKey, { name: "AES-GCM" }, true, [
    "encrypt",
    "decrypt",
  ]);
}

/**
 * Encrypts a string using AES-GCM 256.
 * @param {string} data
 * @param {CryptoKey} key
 * @returns {Promise<{ iv: string, ciphertext: string, tag: string }>}
 */
async function encryptBlob(data, key) {
  const enc = new TextEncoder();
  const iv = crypto.getRandomValues(new Uint8Array(12));
  const encoded = enc.encode(data);
  const encrypted = await crypto.subtle.encrypt(
    { name: "AES-GCM", iv },
    key,
    encoded
  );
  // ciphertext includes tag at the end (AES-GCM)
  // We'll split tag (last 16 bytes) for API compatibility
  const encryptedArr = new Uint8Array(encrypted);
  const tag = encryptedArr.slice(-16);
  const ciphertext = encryptedArr.slice(0, -16);
  return {
    iv: btoa(String.fromCharCode(...iv)),
    ciphertext: btoa(String.fromCharCode(...ciphertext)),
    tag: btoa(String.fromCharCode(...tag)),
  };
}

/**
 * Decrypts a blob using AES-GCM 256.
 * @param {{ iv: string, ciphertext: string, tag: string }} encrypted
 * @param {CryptoKey} key
 * @returns {Promise<string>}
 */
async function decryptBlob(encrypted, key) {
  const dec = new TextDecoder();
  const iv = Uint8Array.from(atob(encrypted.iv), (c) => c.charCodeAt(0));
  const ciphertext = Uint8Array.from(atob(encrypted.ciphertext), (c) =>
    c.charCodeAt(0)
  );
  const tag = Uint8Array.from(atob(encrypted.tag), (c) => c.charCodeAt(0));
  // Reconstruct full encrypted buffer (ciphertext + tag)
  const full = new Uint8Array(ciphertext.length + tag.length);
  full.set(ciphertext);
  full.set(tag, ciphertext.length);
  const decrypted = await crypto.subtle.decrypt(
    { name: "AES-GCM", iv },
    key,
    full
  );
  return dec.decode(decrypted);
}

/**
 * Async generator yielding frames with speech (simulated).
 * @returns {AsyncIterable<{ frame: ArrayBuffer, timestamp: number }>}
 */
async function* recordAndDetectVoice() {
  // Simulate 5 frames with 100ms interval
  for (let i = 0; i < 5; i++) {
    const frame = new Uint8Array([i, i + 1, i + 2]).buffer;
    yield { frame, timestamp: Date.now() };
    await new Promise((r) => setTimeout(r, 100));
  }
}

/**
 * Uploads a blob to the API endpoint.
 * @param {Blob} blob
 * @param {string} apiUrl
 * @param {string} token
 * @returns {Promise<string>} blobKey
 */
async function uploadBlob(blob, apiUrl, token) {
  // Simulate upload: return a fake blobKey
  await new Promise((r) => setTimeout(r, 200));
  return "fake-blob-key";
}

/**
 * Downloads and decrypts a blob from the API.
 * @param {string} blobKey
 * @param {string} apiUrl
 * @param {CryptoKey} key
 * @returns {Promise<string>}
 */
async function downloadAndDecrypt(blobKey, apiUrl, key) {
  // Simulate download: return a fake decrypted string
  await new Promise((r) => setTimeout(r, 200));
  return "decrypted result";
}

export {
  generateKey,
  importKey,
  encryptBlob,
  decryptBlob,
  recordAndDetectVoice,
  uploadBlob,
  downloadAndDecrypt,
};
